namespace sv_a23cac205b434bcd963eda92319b1803.Services;

public class DoctorInfo
{
    public string Name { get; set; } = "";
    public bool AcceptsSelfPay { get; set; }
}

public class PatientValidationResult
{
    public bool IsValid => Errors.Count == 0;
    public Dictionary<string, List<string>> Errors { get; set; } = new();
}

public interface IAppointmentService
{
    Task<List<DoctorInfo>> GetDoctorsAsync();
    Task<List<string>> GetAvailableTimeSlotsAsync(string doctorName, DateOnly date);
    Task<PatientValidationResult> ValidatePatientAsync(
        string email, string insuranceProvider, string doctorName, string timeSlot);
}

public class AppointmentService : IAppointmentService
{
    private static readonly List<DoctorInfo> Doctors =
    [
        new() { Name = "Dr. Smith", AcceptsSelfPay = false },
        new() { Name = "Dr. Johnson", AcceptsSelfPay = true },
        new() { Name = "Dr. Williams", AcceptsSelfPay = true },
        new() { Name = "Dr. Brown", AcceptsSelfPay = false },
    ];

    public Task<List<DoctorInfo>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctorName, DateOnly date)
    {
        List<string> slots =
        [
            "9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM",
            "11:00 AM", "1:00 PM", "1:30 PM", "2:00 PM",
            "2:30 PM", "3:00 PM", "3:30 PM", "4:00 PM",
        ];
        return Task.FromResult(slots);
    }

    public Task<PatientValidationResult> ValidatePatientAsync(
        string email, string insuranceProvider, string doctorName, string timeSlot)
    {
        var result = new PatientValidationResult();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors.TryAdd("Email", []);
            result.Errors["Email"].Add("Account has outstanding balance");
        }

        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal))
        {
            var doctor = Doctors.FirstOrDefault(d => d.Name == doctorName);
            if (doctor is { AcceptsSelfPay: false })
            {
                result.Errors.TryAdd("PreferredDoctor", []);
                result.Errors["PreferredDoctor"].Add("Selected doctor does not accept self-pay patients");
            }
        }

        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            result.Errors.TryAdd("TimeSlot", []);
            result.Errors["TimeSlot"].Add("This slot is no longer available");
        }

        return Task.FromResult(result);
    }
}

